import type { NextRequest } from "next/server";
import { deleteScenario, getScenario, saveScenario } from "@/lib/scenario-manager";

export async function GET(_: NextRequest, { params }: { params: { id: string } }) {
  const scenario = getScenario(params.id);

  if (!scenario) {
    return NextResponse.json({ success: false, error: "Not found" }, { status: 404 });
  }

  return NextResponse.json({ success: true, data: scenario });
}

export async function PUT(request: NextRequest, { params }: { params: { id: string } }) {
  try {
    const existing = getScenario(params.id);

    if (!existing) {
      return NextResponse.json({ success: false, error: "Not found" }, { status: 404 });
    }

    const body = await request.json();
    const updated = {
      ...existing,
      ...body,
      id: params.id,
      updatedAt: new Date().toISOString(),
    };

    saveScenario(updated);

    return NextResponse.json({ success: true, data: updated });
  } catch (error) {
    return NextResponse.json({ success: false, error: String(error) }, { status: 500 });
  }
}

export async function DELETE(_: NextRequest, { params }: { params: { id: string } }) {
  const deleted = deleteScenario(params.id);

  if (!deleted) {
    return NextResponse.json({ success: false, error: "Not found" }, { status: 404 });
  }

  return NextResponse.json({ success: true });
}
