import type { RunProgress } from "@/lib/types";

function getProgressPercent(progress: RunProgress): number {
  if (progress.status === "completed") {
    return 100;
  }

  if (progress.totalStepsOverall === 0) {
    return progress.status === "savingSnapshot" ? 95 : 5;
  }

  const base = Math.round((progress.completedStepsOverall / progress.totalStepsOverall) * 100);

  if (progress.status === "savingSnapshot") {
    return Math.max(base, 95);
  }

  return Math.max(base, progress.status === "running" ? 5 : 0);
