, "content": "import fs from "node:fs";
import path from "node:path";
import type { GlobalSettings } from "./types.js";

const SETTINGS_DIR = path.join(process.cwd(), "data", "settings");
const SETTINGS_FILE = path.join(SETTINGS_DIR, "global.json");

function ensureDir() {
  if (!fs.existsSync(SETTINGS_DIR)) {
    fs.mkdirSync(SETTINGS_DIR, { recursive: true });
  }
}

export function readGlobalSettings(): GlobalSettings | null {
  if (!fs.existsSync(SETTINGS_FILE)) {
    return null;
  }

  return JSON.parse(fs.readFileSync(SETTINGS_FILE, "utf-8")) as GlobalSettings;
}

export function saveGlobalSettings(settings: GlobalSettings): void {
  ensureDir();
  fs.writeFileSync(SETTINGS_FILE, JSON.stringify(settings, null, 2), "utf-8");
}
