```ts
export function normalizeUrl(input: string, base?: string): string | null {
  try {
    const url = base ? new URL(input, base) : new URL(input);
    url.protocol = url.protocol.toLowerCase();
    url.hostname = url.hostname.toLowerCase();
    url.hash = "";
    if (url.pathname.length > 1 && url.pathname.endsWith("/")) {
      url.pathname = url.pathname.replace(/\/+$/, "");
    }
    return url.toString();
  } catch {
    return null;
  }
}

export function isHttpUrl(input: string): boolean {
  try {
    const protocol = new URL(input).protocol;
    return protocol === "http:" || protocol === "https:";
  } catch {
    return false;
  }
}

export function sameOrigin(a: string, b: string, allowSubdomains: boolean): boolean {
  try {
    const left = new URL(a);
    const right = new URL(b);
    if (left.protocol !== right.protocol) return false;
    if (allowSubdomains) {
      const leftRoot = left.hostname.split(".").slice(-2).join(".");
      const rightRoot = right.hostname.split(".").slice(-2).join(".");
      return leftRoot === rightRoot;
    }
    return left.host === right.host;
  } catch {
    return false;
  }
}
```

