import { test, expect } from "@playwright/test";

test("site regression pipeline end-to-end", async ({ request }) => {
  const id = `e2e-${Date.now()}`;

  let res = await request.post("/api/sites", {
    data: {
      id, name: id,
      crawl: {
        startUrls: ["https://example.com/"],
        maxDepth: 0,
        maxPages: 1,
        allowSubdomains: false,
      },
      visual: {
        enabled: true,
        maskSelectors: [],
        threshold: 0.1,
        maxDiffRatio: 0.0,
        viewport: { width: 800, height: 600 },
      },
      dom: { enabled: true, ignoreSelectors: [], normalizeWhitespace: true },
      createdAt: "",
      updatedAt: "",
    },
  });
  expect((await res.json()).success).toBe(true);

  res = await request.post(`/api/sites/${id}/run`);
  const runResult = await res.json();
  expect(runResult.success).toBe(true);
  const runId = runResult.data.runId as string;

  res = await request.post(`/api/sites/${id}/baseline`, { data: { runId } });
  expect((await res.json()).success).toBe(true);

  res = await request.post(`/api/sites/${id}/compare`);
  const compare = await res.json();
  expect(compare.success).toBe(true);
  expect(["identical", "different"]).toContain(compare.data.report.overall);

  await request.delete(`/api/sites/${id}`);
});
